// Minimal local Alpine-compatible runtime for AAAAT dashboard primitives.
// Supports the Alpine directives used by the server-rendered dashboard: x-data,
// x-show, x-text, x-bind/:, @click, @change, and x-cloak.
(function(){
  if(window.Alpine&&window.Alpine.start){return;}
  function evalIn(expr,data,event){return Function('$data','$event','with($data){return ('+expr+')}')(data,event);}
  function runIn(expr,data,event){return Function('$data','$event','with($data){'+expr+'}')(data,event);}
  function parseData(expr){return Function('return ('+(expr||'{}')+')')();}
  function bindMethods(data){Object.keys(data).forEach(function(key){if(typeof data[key]==='function'){data[key]=data[key].bind(data);}});}
  function ownerOf(el){return el.closest('[x-data]');}
  function boolAttr(el,name,value){el[name]=!!value;if(value){el.setAttribute(name,name);}else{el.removeAttribute(name);}}
  function setBound(el,name,value){
    if(name==='checked'||name==='disabled'){boolAttr(el,name,value);return;}
    if(name==='style'){el.setAttribute('style',value==null?'':String(value));return;}
    if(value===false||value==null){el.removeAttribute(name);return;}
    el.setAttribute(name,String(value));
  }
  function initComponent(root){
    if(root.__aaaatAlpineComponent){return;}
    var data=parseData(root.getAttribute('x-data'));
    bindMethods(data);
    var nodes=[root].concat(Array.from(root.querySelectorAll('*')).filter(function(el){return ownerOf(el)===root;}));
    function update(){
      nodes.forEach(function(el){
        Array.from(el.attributes).forEach(function(attr){
          var name=attr.name;
          var expr=attr.value;
          if(name==='x-text'){
            var value=evalIn(expr,data);
            el.textContent=value==null?'':String(value);
          }else if(name.indexOf('x-bind:')===0){
            setBound(el,name.slice(7),evalIn(expr,data));
          }else if(name.charAt(0)===':'){
            setBound(el,name.slice(1),evalIn(expr,data));
          }
        });
        if(el.hasAttribute('x-show')){
          el.style.display=evalIn(el.getAttribute('x-show'),data)?'':'none';
        }
        if(el.hasAttribute('x-cloak')){el.removeAttribute('x-cloak');}
      });
    }
    nodes.forEach(function(el){
      Array.from(el.attributes).forEach(function(attr){
        var name=attr.name;
        if(name.charAt(0)==='@'||name.indexOf('x-on:')===0){
          var eventName=name.charAt(0)==='@'?name.slice(1):name.slice(5);
          var key=name+'='+attr.value;
          el.__aaaatAlpineListeners=el.__aaaatAlpineListeners||{};
          if(!el.__aaaatAlpineListeners[key]){
            el.addEventListener(eventName,function(event){runIn(attr.value,data,event);update();});
            el.__aaaatAlpineListeners[key]=true;
          }
        }
      });
    });
    root.__aaaatAlpineComponent={data:data,update:update};
    update();
  }
  function start(root){
    root=root||document;
    Array.from(root.querySelectorAll('[x-data]')).forEach(initComponent);
  }
  window.Alpine={start:start};
  document.addEventListener('DOMContentLoaded',function(){start(document);});
  document.addEventListener('htmx:afterSwap',function(event){start(event.target||document);});
})();
